export interface SongConfig {
  lyrics: string;
  stylePrompt: string;
  excludeTags: string;
  styleInfluence: number; // 0.0 to 1.0
  weirdness: number; // 0.0 to 1.0
  audioInfluence: number; // 0.0 (Instrumental) to 1.0 (Vocal heavy) - though Suno usually handles this via tags, we simulate a "slider" for instruction
}

export type SunoTag = {
  id: string;
  label: string;
  category: 'structure' | 'style' | 'instrument' | 'meta';
};

export const COMMON_TAGS: SunoTag[] = [
  { id: '[Intro]', label: 'Intro', category: 'structure' },
  { id: '[Verse]', label: 'Verse', category: 'structure' },
  { id: '[Chorus]', label: 'Chorus', category: 'structure' },
  { id: '[Bridge]', label: 'Bridge', category: 'structure' },
  { id: '[Pre-Chorus]', label: 'Pre-Chorus', category: 'structure' },
  { id: '[Outro]', label: 'Outro', category: 'structure' },
  { id: '[Instrumental Break]', label: 'Inst. Break', category: 'structure' },
  { id: '[Drop]', label: 'Drop', category: 'style' },
  { id: '[Hook]', label: 'Hook', category: 'structure' },
  { id: '[Solo]', label: 'Solo', category: 'instrument' },
  { id: '[Fade Out]', label: 'Fade Out', category: 'meta' },
  { id: '[End]', label: 'End', category: 'meta' },
];

import { GoogleGenAI, Type } from "@google/genai";
import { SongConfig } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateSunoData = async (description: string): Promise<SongConfig> => {
  const modelId = "gemini-3-flash-preview";

  const systemInstruction = `
    You are an expert music producer and lyricist specializing in prompting for Suno AI (v3.5/v4).
    Your task is to take a user's song description and generate:
    1. Complete Lyrics formatted specifically for Suno (using tags like [Verse 1], [Chorus], [Outro], etc.).
    2. A concise, effective "Style Prompt" (genre, instruments, tempo, mood).
    3. An "Exclude" prompt (elements to avoid).
    4. Recommended numerical settings for Suno parameters (simulated).

    RULES FOR LYRICS:
    - Use standard Suno metatags: [Intro], [Verse], [Chorus], [Bridge], [Outro], [Instrumental].
    - Ensure rhyme schemes fit the genre.

    RULES FOR STYLE PROMPT:
    - Keep it under 120 characters if possible.
    - Focus on sub-genres and vibe.

    RULES FOR PARAMETERS:
    - weirdness: 0 to 1 scale.
    - styleInfluence: 0 to 1 scale (alpha/beta feature).
    - audioInfluence: 0 (pure instrumental) to 1 (vocal focus).
  `;

  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: description,
      config: {
        systemInstruction,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            lyrics: { type: Type.STRING, description: "The full lyrics with tags" },
            stylePrompt: { type: Type.STRING, description: "Comma separated style tags" },
            excludeTags: { type: Type.STRING, description: "Styles to exclude" },
            styleInfluence: { type: Type.NUMBER, description: "0.0 to 1.0" },
            weirdness: { type: Type.NUMBER, description: "0.0 to 1.0" },
            audioInfluence: { type: Type.NUMBER, description: "0.0 to 1.0" }
          },
          required: ["lyrics", "stylePrompt", "excludeTags", "styleInfluence", "weirdness", "audioInfluence"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    return JSON.parse(text) as SongConfig;

  } catch (error) {
    console.error("Gemini generation error:", error);
    throw error;
  }
};

import React from 'react';

interface KnobProps {
  value: number; // 0 to 1
  label: string;
  color: 'cyan' | 'pink' | 'acid';
}

const Knob: React.FC<KnobProps> = ({ value, label, color }) => {
  // Convert 0-1 to degrees (-135 to 135)
  const minDeg = -135;
  const maxDeg = 135;
  const deg = minDeg + (value * (maxDeg - minDeg));

  const colorMap = {
    cyan: '#00f0ff',
    pink: '#ff003c',
    acid: '#ccff00',
  };

  const activeColor = colorMap[color];

  return (
    <div className="flex flex-col items-center justify-center gap-2 select-none group">
      <div className="relative w-16 h-16 md:w-20 md:h-20 flex items-center justify-center">
        {/* Outer Ring Track */}
        <svg className="w-full h-full transform -rotate-90 overflow-visible" viewBox="0 0 100 100">
           <circle
            cx="50"
            cy="50"
            r="40"
            stroke="#27272a"
            strokeWidth="8"
            fill="none"
            strokeDasharray="251.2"
            strokeDashoffset="62.8" /* Leaves the bottom gap */
            className="opacity-50"
          />
           {/* Active Value Arc */}
           <circle
            cx="50"
            cy="50"
            r="40"
            stroke={activeColor}
            strokeWidth="8"
            fill="none"
            strokeDasharray="251.2"
            strokeDashoffset={251.2 - (251.2 * 0.75 * value)}
            strokeLinecap="round"
            className="drop-shadow-[0_0_8px_rgba(255,255,255,0.3)]"
          />
        </svg>

        {/* Knob Body */}
        <div 
          className="absolute w-10 h-10 md:w-12 md:h-12 rounded-full bg-synth-panel border-2 border-synth-border shadow-[inset_0_1px_4px_rgba(0,0,0,0.5)] flex items-center justify-center transition-transform duration-700 ease-out"
          style={{ transform: `rotate(${deg}deg)` }}
        >
            <div className="w-1 h-3 md:h-4 bg-white rounded-full absolute -top-1 shadow-[0_0_5px_white]"></div>
        </div>

        {/* Value Text Overlay */}
        <div className="absolute -bottom-6 font-mono text-xs text-white/70 tracking-widest">
            {(value).toFixed(2)}
        </div>
      </div>
      <span className={`text-[10px] md:text-xs uppercase tracking-[0.2em] font-bold ${color === 'cyan' ? 'text-neon-cyan' : color === 'pink' ? 'text-neon-pink' : 'text-acid-green'}`}>
        {label}
      </span>
    </div>
  );
};

export default Knob;

